50: /**
51:  * SaslServer implementation for SASL/SCRAM. This server is configured with a callback
52:  * handler for integration with a credential manager. Kafka brokers provide callbacks
53:  * based on a Zookeeper-based password store.
54:  *
55:  * @see <a href="https://tools.ietf.org/html/rfc5802">RFC 5802</a>
56:  */
57: public class ScramSaslServer implements SaslServer {
58: 
59:     private static final Logger log = LoggerFactory.getLogger(ScramSaslServer.class);
60:     private static final Set<String> SUPPORTED_EXTENSIONS = Set.of(ScramLoginModule.TOKEN_AUTH_CONFIG);
61: 
62:     enum State {
63:         RECEIVE_CLIENT_FIRST_MESSAGE,
64:         RECEIVE_CLIENT_FINAL_MESSAGE,
65:         COMPLETE,
66:         FAILED
67:     }
68: 
69:     private final ScramMechanism mechanism;
70:     private final ScramFormatter formatter;
71:     private final CallbackHandler callbackHandler;
72:     private State state;
73:     private ClientFirstMessage clientFirstMessage;
74:     private ServerFirstMessage serverFirstMessage;
75:     private ScramExtensions scramExtensions;
76:     private ScramCredential scramCredential;
77:     private String authorizationId;
78:     private Long tokenExpiryTimestamp;
79: 
80:     public ScramSaslServer(ScramMechanism mechanism, Map<String, ?> props, CallbackHandler callbackHandler) throws NoSuchAlgorithmException {
81:         this.mechanism = mechanism;
82:         this.formatter = new ScramFormatter(mechanism);
83:         this.callbackHandler = callbackHandler;
84:         setState(State.RECEIVE_CLIENT_FIRST_MESSAGE);
85:     }
86: 
87:     /**
88:      * @throws SaslAuthenticationException if the requested authorization id is not the same as username.
89:      * <p>
90:      * <b>Note:</b> This method may throw {@link SaslAuthenticationException} to provide custom error messages
91:      * to clients. But care should be taken to avoid including any information in the exception message that
92:      * should not be leaked to unauthenticated clients. It may be safer to throw {@link SaslException} in
93:      * most cases so that a standard error message is returned to clients.
94:      * </p>
95:      */
96:     @Override
97:     public byte[] evaluateResponse(byte[] response) throws SaslException, SaslAuthenticationException {
98:         try {
99:             switch (state) {
100:                 case RECEIVE_CLIENT_FIRST_MESSAGE:
101:                     this.clientFirstMessage = new ClientFirstMessage(response);
102:                     this.scramExtensions = clientFirstMessage.extensions();
103:                     if (!SUPPORTED_EXTENSIONS.containsAll(scramExtensions.map().keySet())) {
104:                         log.debug("Unsupported extensions will be ignored, supported {}, provided {}",
105:                                 SUPPORTED_EXTENSIONS, scramExtensions.map().keySet());
106:                     }
107:                     String serverNonce = formatter.secureRandomString();
108:                     try {
109:                         String saslName = clientFirstMessage.saslName();
110:                         String username = ScramFormatter.username(saslName);
111:                         NameCallback nameCallback = new NameCallback("username", username);
112:                         ScramCredentialCallback credentialCallback;
113:                         if (scramExtensions.tokenAuthenticated()) {
114:                             DelegationTokenCredentialCallback tokenCallback = new DelegationTokenCredentialCallback();
115:                             credentialCallback = tokenCallback;
116:                             callbackHandler.handle(new Callback[]{nameCallback, tokenCallback});
117:                             if (tokenCallback.tokenOwner() == null)
118:                                 throw new SaslException("Token Authentication failed: Invalid tokenId : " + username);
119:                             this.authorizationId = tokenCallback.tokenOwner();
120:                             this.tokenExpiryTimestamp = tokenCallback.tokenExpiryTimestamp();
121:                         } else {
122:                             credentialCallback = new ScramCredentialCallback();
123:                             callbackHandler.handle(new Callback[]{nameCallback, credentialCallback});
124:                             this.authorizationId = username;
125:                             this.tokenExpiryTimestamp = null;
126:                         }
127:                         this.scramCredential = credentialCallback.scramCredential();
128:                         if (scramCredential == null)
129:                             throw new SaslException("Authentication failed: Invalid user credentials");
130:                         String authorizationIdFromClient = clientFirstMessage.authorizationId();
131:                         if (!authorizationIdFromClient.isEmpty() && !authorizationIdFromClient.equals(username))
132:                             throw new SaslAuthenticationException("Authentication failed: Client requested an authorization id that is different from username");
133: 
134:                         if (scramCredential.iterations() < mechanism.minIterations())
135:                             throw new SaslException("Iterations " + scramCredential.iterations() +  " is less than the minimum " + mechanism.minIterations() + " for " + mechanism);
136:                         this.serverFirstMessage = new ServerFirstMessage(clientFirstMessage.nonce(),
137:                                 serverNonce,
138:                                 scramCredential.salt(),
139:                                 scramCredential.iterations());
140:                         setState(State.RECEIVE_CLIENT_FINAL_MESSAGE);
141:                         return serverFirstMessage.toBytes();
142:                     } catch (SaslException | AuthenticationException e) {
143:                         throw e;
144:                     } catch (Throwable e) {
145:                         throw new SaslException("Authentication failed: Credentials could not be obtained", e);
146:                     }
147: 
148:                 case RECEIVE_CLIENT_FINAL_MESSAGE:
149:                     try {
150:                         ClientFinalMessage clientFinalMessage = new ClientFinalMessage(response);
151:                         if (!clientFinalMessage.nonce().endsWith(serverFirstMessage.nonce())) {
152:                             throw new SaslException("Invalid client nonce in the final client message.");
153:                         }
154:                         verifyClientProof(clientFinalMessage);
155:                         byte[] serverKey = scramCredential.serverKey();
156:                         byte[] serverSignature = formatter.serverSignature(serverKey, clientFirstMessage, serverFirstMessage, clientFinalMessage);
157:                         ServerFinalMessage serverFinalMessage = new ServerFinalMessage(null, serverSignature);
158:                         clearCredentials();
159:                         setState(State.COMPLETE);
160:                         return serverFinalMessage.toBytes();
161:                     } catch (InvalidKeyException e) {
162:                         throw new SaslException("Authentication failed: Invalid client final message", e);
163:                     }
164: 
165:                 default:
166:                     throw new IllegalSaslStateException("Unexpected challenge in Sasl server state " + state);
167:             }
168:         } catch (SaslException | AuthenticationException e) {
169:             clearCredentials();
170:             setState(State.FAILED);
171:             throw e;
172:         }
173:     }
174: 
175:     @Override
176:     public String getAuthorizationID() {
177:         if (!isComplete())
178:             throw new IllegalStateException("Authentication exchange has not completed");
179:         return authorizationId;
180:     }
181: 
182:     @Override
183:     public String getMechanismName() {
184:         return mechanism.mechanismName();
185:     }
186: 
187:     @Override
188:     public Object getNegotiatedProperty(String propName) {
189:         if (!isComplete())
190:             throw new IllegalStateException("Authentication exchange has not completed");
191:         if (SaslInternalConfigs.CREDENTIAL_LIFETIME_MS_SASL_NEGOTIATED_PROPERTY_KEY.equals(propName))
192:             return tokenExpiryTimestamp; // will be null if token not used
193:         if (SUPPORTED_EXTENSIONS.contains(propName))
194:             return scramExtensions.map().get(propName);
195:         else
196:             return null;
197:     }
198: 
199:     @Override
200:     public boolean isComplete() {
201:         return state == State.COMPLETE;
202:     }
203: 
204:     @Override
205:     public byte[] unwrap(byte[] incoming, int offset, int len) {
206:         if (!isComplete())
207:             throw new IllegalStateException("Authentication exchange has not completed");
208:         return Arrays.copyOfRange(incoming, offset, offset + len);
209:     }
210: 
211:     @Override
212:     public byte[] wrap(byte[] outgoing, int offset, int len) {
213:         if (!isComplete())
214:             throw new IllegalStateException("Authentication exchange has not completed");
215:         return Arrays.copyOfRange(outgoing, offset, offset + len);
216:     }
217: 
218:     @Override
219:     public void dispose() {
220:     }
221: 
222:     private void setState(State state) {
223:         log.debug("Setting SASL/{} server state to {}", mechanism, state);
224:         this.state = state;
225:     }
226: 
227:     // Visible for testing
228:     void verifyClientProof(ClientFinalMessage clientFinalMessage) throws SaslException {
229:         try {
230:             byte[] expectedStoredKey = scramCredential.storedKey();
231:             byte[] clientSignature = formatter.clientSignature(expectedStoredKey, clientFirstMessage, serverFirstMessage, clientFinalMessage);
232:             byte[] computedStoredKey = formatter.storedKey(clientSignature, clientFinalMessage.proof());
233:             if (!MessageDigest.isEqual(computedStoredKey, expectedStoredKey))
234:                 throw new SaslException("Invalid client credentials");
235:         } catch (InvalidKeyException e) {
236:             throw new SaslException("Sasl client verification failed", e);
237:         }
238:     }
239: 
240:     private void clearCredentials() {
241:         scramCredential = null;
242:         clientFirstMessage = null;
243:         serverFirstMessage = null;
244:     }
245: 
246:     public static class ScramSaslServerFactory implements SaslServerFactory {
247: 
248:         @Override
249:         public SaslServer createSaslServer(String mechanism, String protocol, String serverName, Map<String, ?> props, CallbackHandler cbh)
250:             throws SaslException {
251: 
252:             if (!ScramMechanism.isScram(mechanism)) {
253:                 throw new SaslException(String.format("Requested mechanism '%s' is not supported. Supported mechanisms are '%s'.",
254:                         mechanism, ScramMechanism.mechanismNames()));
255:             }
256:             try {
257:                 return new ScramSaslServer(ScramMechanism.forMechanismName(mechanism), props, cbh);
258:             } catch (NoSuchAlgorithmException e) {
259:                 throw new SaslException("Hash algorithm not supported for mechanism " + mechanism, e);
260:             }
261:         }
262: 
263:         @Override
264:         public String[] getMechanismNames(Map<String, ?> props) {
265:             Collection<String> mechanisms = ScramMechanism.mechanismNames();
266:             return mechanisms.toArray(new String[0]);
267:         }
268:     }
269: }
