346:             throw new IllegalArgumentException(
347:                     "Invalid saslHandshakeReceive in server-side re-authentication context: null");
348:         SaslServerAuthenticator previousSaslServerAuthenticator = (SaslServerAuthenticator) reauthenticationContext.previousAuthenticator();
349:         reauthInfo.reauthenticating(previousSaslServerAuthenticator.saslMechanism,
350:                 previousSaslServerAuthenticator.principal(), reauthenticationContext.reauthenticationBeginNanos());
