502:     /**
503:      * @throws InvalidRequestException if the request is not in Kafka format or if the API key is invalid. Clients
504:      * that support SASL without support for KIP-43 (e.g. Kafka Clients 0.9.x) are in the former bucket - the first
505:      * packet such clients send is a GSSAPI token starting with 0x60.
506:      */
507:     private void handleKafkaRequest(byte[] requestBytes) throws IOException, AuthenticationException {
508:         try {
509:             ByteBuffer requestBuffer = ByteBuffer.wrap(requestBytes);
510:             RequestHeader header = RequestHeader.parse(requestBuffer);
511:             ApiKeys apiKey = header.apiKey();
512: 
513:             // Raise an error prior to parsing if the api cannot be handled at this layer. This avoids
514:             // unnecessary exposure to some of the more complex schema types.
515:             if (apiKey != ApiKeys.API_VERSIONS && apiKey != ApiKeys.SASL_HANDSHAKE)
516:                 throw new InvalidRequestException("Unexpected Kafka request of type " + apiKey + " during SASL handshake.");
517: 
518:             LOG.debug("Handling Kafka request {} during {}", apiKey, reauthInfo.authenticationOrReauthenticationText());
519: 
520:             RequestContext requestContext = new RequestContext(header, connectionId, clientAddress(), Optional.of(clientPort()),
521:                     KafkaPrincipal.ANONYMOUS, listenerName, securityProtocol, ClientInformation.EMPTY, false);
522:             RequestAndSize requestAndSize = requestContext.parseRequest(requestBuffer);
523: 
524:             // A valid Kafka request was received, we can now update the sasl state
525:             if (saslState == SaslState.INITIAL_REQUEST)
526:                 setSaslState(SaslState.HANDSHAKE_OR_VERSIONS_REQUEST);
527: 
528:             if (apiKey == ApiKeys.API_VERSIONS)
529:                 handleApiVersionsRequest(requestContext, (ApiVersionsRequest) requestAndSize.request);
530:             else {
531:                 String clientMechanism = handleHandshakeRequest(requestContext, (SaslHandshakeRequest) requestAndSize.request);
532:                 if (!reauthInfo.reauthenticating() || reauthInfo.saslMechanismUnchanged(clientMechanism)) {
533:                     createSaslServer(clientMechanism);
534:                     setSaslState(SaslState.AUTHENTICATE);
535:                 }
536:             }
537:         } catch (InvalidRequestException e) {
538:             if (saslState == SaslState.INITIAL_REQUEST) {
539:                 // InvalidRequestException is thrown if the request is not in Kafka format or if the API key is invalid.
540:                 // If it's the initial request, this could be an ancient client (see method documentation for more details),
541:                 // a client configured with the wrong security protocol or a non kafka-client altogether (eg http client).
542:                 throw new InvalidRequestException("Invalid request, potential reasons: kafka client configured with the " +
543:                     "wrong security protocol, it does not support KIP-43 or it is not a kafka client.", e);
544:             }
545:             throw e;
546:         }
547:     }
548: 
549:     private String handleHandshakeRequest(RequestContext context, SaslHandshakeRequest handshakeRequest) throws IOException, UnsupportedSaslMechanismException {
550:         String clientMechanism = handshakeRequest.data().mechanism();
551:         short version = context.header.apiVersion();
552:         if (version >= 1)
553:             this.enableKafkaSaslAuthenticateHeaders(true);
554:         if (enabledMechanisms.contains(clientMechanism)) {
555:             LOG.debug("Using SASL mechanism '{}' provided by client", clientMechanism);
556:             sendKafkaResponse(context, new SaslHandshakeResponse(
557:                     new SaslHandshakeResponseData().setErrorCode(Errors.NONE.code()).setMechanisms(enabledMechanisms)));
558:             return clientMechanism;
559:         } else {
560:             LOG.debug("SASL mechanism '{}' requested by client is not supported", clientMechanism);
561:             buildResponseOnAuthenticateFailure(context, new SaslHandshakeResponse(
562:                     new SaslHandshakeResponseData().setErrorCode(Errors.UNSUPPORTED_SASL_MECHANISM.code()).setMechanisms(enabledMechanisms)));
563:             throw new UnsupportedSaslMechanismException("Unsupported SASL mechanism " + clientMechanism);
564:         }
565:     }
