615:     /**
616:      * Information related to re-authentication
617:      */
618:     private class ReauthInfo {
619:         public String previousSaslMechanism;
620:         public KafkaPrincipal previousKafkaPrincipal;
621:         public long reauthenticationBeginNanos;
622:         public Long sessionExpirationTimeNanos;
623:         public boolean connectedClientSupportsReauthentication;
624:         public long authenticationEndNanos;
625:         public String badMechanismErrorMessage;
626: 
627:         public void reauthenticating(String previousSaslMechanism, KafkaPrincipal previousKafkaPrincipal,
628:                 long reauthenticationBeginNanos) {
629:             this.previousSaslMechanism = Objects.requireNonNull(previousSaslMechanism);
630:             this.previousKafkaPrincipal = Objects.requireNonNull(previousKafkaPrincipal);
631:             this.reauthenticationBeginNanos = reauthenticationBeginNanos;
632:         }
633: 
634:         public boolean reauthenticating() {
635:             return previousSaslMechanism != null;
636:         }
637: 
638:         public String authenticationOrReauthenticationText() {
639:             return reauthenticating() ? "re-authentication" : "authentication";
640:         }
641: 
642:         public void ensurePrincipalUnchanged(KafkaPrincipal reauthenticatedKafkaPrincipal) throws SaslAuthenticationException {
643:             if (!previousKafkaPrincipal.equals(reauthenticatedKafkaPrincipal)) {
644:                 throw new SaslAuthenticationException(String.format(
645:                         "Cannot change principals during re-authentication from %s.%s: %s.%s",
646:                         previousKafkaPrincipal.getPrincipalType(), previousKafkaPrincipal.getName(),
647:                         reauthenticatedKafkaPrincipal.getPrincipalType(), reauthenticatedKafkaPrincipal.getName()));
648:             }
649:         }
650: 
651:         /*
652:          * We define the REAUTH_BAD_MECHANISM state because the failed re-authentication
653:          * metric does not get updated if we send back an error immediately upon the
654:          * start of re-authentication.
655:          */
656:         public boolean saslMechanismUnchanged(String clientMechanism) {
657:             if (previousSaslMechanism.equals(clientMechanism))
658:                 return true;
659:             badMechanismErrorMessage = String.format(
660:                     "SASL mechanism '%s' requested by client is not supported for re-authentication of mechanism '%s'",
661:                     clientMechanism, previousSaslMechanism);
662:             LOG.debug(badMechanismErrorMessage);
663:             setSaslState(SaslState.REAUTH_BAD_MECHANISM);
664:             return false;
665:         }
666: 
667:         private long calcCompletionTimesAndReturnSessionLifetimeMs() {
668:             long retvalSessionLifetimeMs = 0L;
669:             long authenticationEndMs = time.milliseconds();
670:             authenticationEndNanos = time.nanoseconds();
671:             Long credentialExpirationMs = (Long) saslServer
672:                     .getNegotiatedProperty(SaslInternalConfigs.CREDENTIAL_LIFETIME_MS_SASL_NEGOTIATED_PROPERTY_KEY);
673:             Long connectionsMaxReauthMs = connectionsMaxReauthMsByMechanism.get(saslMechanism);
674:             boolean maxReauthSet = connectionsMaxReauthMs != null && connectionsMaxReauthMs > 0;
675: 
676:             if (credentialExpirationMs != null || maxReauthSet) {
677:                 if (credentialExpirationMs == null)
678:                     retvalSessionLifetimeMs = zeroIfNegative(connectionsMaxReauthMs);
679:                 else if (!maxReauthSet)
680:                     retvalSessionLifetimeMs = zeroIfNegative(credentialExpirationMs - authenticationEndMs);
681:                 else
682:                     retvalSessionLifetimeMs = zeroIfNegative(Math.min(credentialExpirationMs - authenticationEndMs, connectionsMaxReauthMs));
683: 
684:                 sessionExpirationTimeNanos = authenticationEndNanos + 1000 * 1000 * retvalSessionLifetimeMs;
685:             }
686: 
687:             if (credentialExpirationMs != null) {
688:                 LOG.debug(
689:                         "Authentication complete; session max lifetime from broker config={} ms, credential expiration={} ({} ms); session expiration = {} ({} ms), sending {} ms to client",
690:                         connectionsMaxReauthMs, new Date(credentialExpirationMs),
691:                         credentialExpirationMs - authenticationEndMs,
692:                         new Date(authenticationEndMs + retvalSessionLifetimeMs), retvalSessionLifetimeMs,
693:                         retvalSessionLifetimeMs);
694:             } else {
695:                 if (sessionExpirationTimeNanos != null)
696:                     LOG.debug(
697:                             "Authentication complete; session max lifetime from broker config={} ms, no credential expiration; session expiration = {} ({} ms), sending {} ms to client",
698:                             connectionsMaxReauthMs, new Date(authenticationEndMs + retvalSessionLifetimeMs),
699:                             retvalSessionLifetimeMs, retvalSessionLifetimeMs);
700:                 else
701:                     LOG.debug(
702:                             "Authentication complete; session max lifetime from broker config={} ms, no credential expiration; no session expiration, sending 0 ms to client",
703:                             connectionsMaxReauthMs);
704:             }
705:             return retvalSessionLifetimeMs;
706:         }
707: 
708:         public Long reauthenticationLatencyMs() {
709:             if (!reauthenticating())
710:                 return null;
711:             // record at least 1 ms if there is some latency
712:             long latencyNanos = authenticationEndNanos - reauthenticationBeginNanos;
713:             return latencyNanos == 0L ? 0L : Math.max(1L, Math.round(latencyNanos / 1000.0 / 1000.0));
714:         }
715: 
716:         private long zeroIfNegative(long value) {
717:             return Math.max(0L, value);
718:         }        
719:     }
720: }
