169:     /**
170:      * Does handshake of transportLayer and authentication using configured authenticator.
171:      * For SSL with client authentication enabled, {@link TransportLayer#handshake()} performs
172:      * authentication. For SASL, authentication is performed by {@link Authenticator#authenticate()}.
173:      */
174:     public void prepare() throws AuthenticationException, IOException {
175:         boolean authenticating = false;
176:         try {
177:             if (!transportLayer.ready())
178:                 transportLayer.handshake();
179:             if (transportLayer.ready() && !authenticator.complete()) {
180:                 authenticating = true;
181:                 authenticator.authenticate();
182:             }
183:         } catch (AuthenticationException e) {
184:             // Clients are notified of authentication exceptions to enable operations to be terminated
185:             // without retries. Other errors are handled as network exceptions in Selector.
186:             String remoteDesc = remoteAddress != null ? remoteAddress.toString() : null;
187:             state = new ChannelState(ChannelState.State.AUTHENTICATION_FAILED, e, remoteDesc);
188:             if (authenticating) {
189:                 delayCloseOnAuthenticationFailure();
190:                 throw new DelayedResponseAuthenticationException(e);
191:             }
192:             throw e;
193:         }
194:         if (ready()) {
195:             ++successfulAuthentications;
196:             state = ChannelState.READY;
197:         }
198:     }
