1029:   private def processChannelException(channelId: String, errorMessage: String, throwable: Throwable): Unit = {
1030:     if (openOrClosingChannel(channelId).isDefined) {
1031:       error(s"Closing socket for $channelId because of error", throwable)
1032:       close(channelId)
