1037:   private def processNewResponses(): Unit = {
1038:     var currentResponse: RequestChannel.Response = null
1039:     while ({currentResponse = dequeueResponse(); currentResponse != null}) {
1040:       val channelId = currentResponse.request.context.connectionId
1041:       try {
1042:         currentResponse match {
1043:           case response: NoOpResponse =>
1044:             // There is no response to send to the client, we need to read more pipelined requests
1045:             // that are sitting in the server's socket buffer
1046:             updateRequestMetrics(response)
1047:             trace(s"Socket server received empty response to send, registering for read: $response")
1048:             // Try unmuting the channel. If there was no quota violation and the channel has not been throttled,
1049:             // it will be unmuted immediately. If the channel has been throttled, it will be unmuted only if the
1050:             // throttling delay has already passed by now.
1051:             handleChannelMuteEvent(channelId, ChannelMuteEvent.RESPONSE_SENT)
1052:             tryUnmuteChannel(channelId)
1053: 
1054:           case response: SendResponse =>
1055:             sendResponse(response, response.responseSend)
1056:           case response: CloseConnectionResponse =>
1057:             updateRequestMetrics(response)
1058:             trace("Closing socket connection actively according to the response code.")
1059:             close(channelId)
1060:           case _: StartThrottlingResponse =>
1061:             handleChannelMuteEvent(channelId, ChannelMuteEvent.THROTTLE_STARTED)
1062:           case _: EndThrottlingResponse =>
1063:             // Try unmuting the channel. The channel will be unmuted only if the response has already been sent out to
1064:             // the client.
1065:             handleChannelMuteEvent(channelId, ChannelMuteEvent.THROTTLE_ENDED)
1066:             tryUnmuteChannel(channelId)
1067:           case _ =>
1068:             throw new IllegalArgumentException(s"Unknown response type: ${currentResponse.getClass}")
1069:         }
1070:       } catch {
1071:         case e: Throwable =>
1072:           processChannelException(channelId, s"Exception while processing response for $channelId", e)
1073:       }
1074:     }
1075:   }
