1079:     val connectionId = response.request.context.connectionId
1080:     trace(s"Socket server received response to send to $connectionId, registering for write and sending data: $response")
1081:     // `channel` can be None if the connection was closed remotely or if selector closed it for being idle for too long
1082:     if (channel(connectionId).isEmpty) {
1083:       warn(s"Attempting to send response via channel for which there is no open connection, connection id $connectionId")
