1087:     // removed from the Selector after discarding any pending staged receives.
1088:     // `openOrClosingChannel` can be None if the selector closed the connection because it was idle for too long
1089:     if (openOrClosingChannel(connectionId).isDefined) {
1090:       selector.send(new NetworkSend(connectionId, responseSend))
